import React, { useEffect, useState } from "react";
import axios from "axios";

function NotificationPanel() {
  const [notifications, setNotifications] = useState([]);
  const [error, setError] = useState("");

  useEffect(() => {
    const token = localStorage.getItem("accessToken"); // откуда у тебя токен

    if (!token) {
      setError("Вы не вошли в систему.");
      return;
    }

    axios
      .get("http://localhost:5001/api/notifications", {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      })
      .then((res) => {
        if (res.data.success) {
          setNotifications(res.data.notifications);
        } else {
          setError("Ошибка загрузки уведомлений.");
        }
      })
      .catch((err) => {
        console.error("Ошибка загрузки уведомлений", err);
        setError("Ошибка подключения к серверу.");
      });
  }, []);

  return (
    <div className="p-4">
      <h3 className="mb-3">🔔 Уведомления</h3>
      {error && <div className="alert alert-danger">{error}</div>}
      {notifications.length === 0 ? (
        <p>Уведомлений нет.</p>
      ) : (
        <ul className="list-group">
          {notifications.map((n) => (
            <li
              key={n.id}
              className={`list-group-item d-flex justify-content-between align-items-start ${
                n.is_read ? "" : "list-group-item-warning"
              }`}
            >
              <div>
                <strong>{n.title}</strong>
                <p className="mb-1">{n.message}</p>
                <small className="text-muted">
                  {new Date(n.created_at).toLocaleString()}
                </small>
              </div>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default NotificationPanel;
